/* ═══════════════════════════════════════════════════════
   PALMKIT LOGO — Uses actual logo image, theme-aware
   ═══════════════════════════════════════════════════════ */

function PalmkitLogo({ className = '' }: { className?: string }) {
  const { theme } = useTheme()
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    const id = requestAnimationFrame(() => setMounted(true))
    return () => cancelAnimationFrame(id)
  }, [])

  if (!mounted) {
    return (
      <div className={`flex items-center gap-2.5 ${className}`}>
        <div className="w-7 h-7 rounded-md bg-[#00A8B5] flex items-center justify-center">
          <Terminal className="w-3.5 h-3.5 text-white" />
        </div>
        <span className="font-display font-semibold text-lg tracking-[-0.02em] text-foreground">
          Palm<span className="text-[#00A8B5]">kit</span>
        </span>
      </div>
    )
  }

  const isDark = theme === 'dark'

  return (
    <div className={`flex items-center ${className}`}>
      <Image
        src={isDark ? '/logo-dark.png' : '/logo-light.png'}
        alt="Palmkit"
        width={120}
        height={36}
        className="h-7 w-auto"
        priority
      />
    </div>
  )
}

/* ═══════════════════════════════════════════════════════
   TYPING ANIMATION — User's favorite, keep it pristine
   ═══════════════════════════════════════════════════════ */

function TypingText({ texts, className = '' }: { texts: string[]; className?: string }) {
  const [currentTextIndex, setCurrentTextIndex] = useState(0)
  const [displayedText, setDisplayedText] = useState('')
  const [isDeleting, setIsDeleting] = useState(false)

  useEffect(() => {
    const currentFullText = texts[currentTextIndex]
    const timeout = setTimeout(() => {
      if (!isDeleting) {
        setDisplayedText(currentFullText.slice(0, displayedText.length + 1))
        if (displayedText.length === currentFullText.length) {
          setTimeout(() => setIsDeleting(true), 2500)
        }
      } else {
        setDisplayedText(currentFullText.slice(0, displayedText.length - 1))
        if (displayedText.length === 0) {
          setIsDeleting(false)
          setCurrentTextIndex((prev) => (prev + 1) % texts.length)
        }
      }
    }, isDeleting ? 25 : 70)
    return () => clearTimeout(timeout)
  }, [displayedText, isDeleting, currentTextIndex, texts])

  return (
    <span className={className}>
      {displayedText}
      <span className="inline-block w-[2px] h-[14px] bg-[#00A8B5] animate-pulse ml-0.5 align-middle" />
    </span>
  )
}

/* ═══════════════════════════════════════════════════════
   SCROLL REVEAL — Staggered, Mistral-elegant timing
   ═══════════════════════════════════════════════════════ */

function Reveal({ children, className = '', delay = 0 }: { children: React.ReactNode; className?: string; delay?: number }) {
  const ref = useRef(null)
  const isInView = useInView(ref, { once: true, margin: '-60px' })

  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 16 }}
      animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 16 }}
      transition={{ duration: 0.5, delay, ease: [0.22, 1, 0.36, 1] }}
      className={className}
    >
      {children}
    </motion.div>
  )
}

/* ═══════════════════════════════════════════════════════
   COPY HOOK
   ═══════════════════════════════════════════════════════ */

function useCopyToClipboard() {
  const [copied, setCopied] = useState(false)
  const copy = useCallback((text: string) => {
    navigator.clipboard.writeText(text)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }, [])
  return { copied, copy }
}

