/* ═══════════════════════════════════════════════════════
   THEME TOGGLE — Professional, footer-embedded
   ═══════════════════════════════════════════════════════ */

function ThemeToggle() {
  const { theme, setTheme } = useTheme()
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    const id = requestAnimationFrame(() => setMounted(true))
    return () => cancelAnimationFrame(id)
  }, [])

  if (!mounted) {
    return <div className="w-14 h-7 rounded-full bg-secondary border border-border" />
  }

  const isDark = theme === 'dark'

  return (
    <button
      onClick={() => setTheme(isDark ? 'light' : 'dark')}
      className="relative w-14 h-7 rounded-full bg-secondary border border-border p-[3px] transition-colors hover:border-[#00A8B5]/30"
      aria-label={`Switch to ${isDark ? 'light' : 'dark'} mode`}
    >
      <Sun className={`absolute left-1.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 transition-opacity ${
        isDark ? 'opacity-25' : 'opacity-60 text-[#00A8B5]'
      }`} />
      <Moon className={`absolute right-1.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 transition-opacity ${
        isDark ? 'opacity-60 text-[#00A8B5]' : 'opacity-25'
      }`} />
      <div className={`w-[20px] h-[20px] rounded-full transition-all duration-300 flex items-center justify-center ${
        isDark
          ? 'translate-x-[24px] bg-[#191928] border border-[#2E2E44]'
          : 'translate-x-0 bg-white border border-[#4CD4B0]/30 shadow-sm'
      }`}>
        {isDark ? (
          <Moon className="w-2.5 h-2.5 text-[#33C4CF]" />
        ) : (
          <Sun className="w-2.5 h-2.5 text-[#00A8B5]" />
        )}
      </div>
    </button>
  )
}

