'use client'

import { useState, useCallback, createContext, useContext, useEffect } from 'react'
import { AnimatePresence, motion } from 'framer-motion'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog'
import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import { Label } from '@/components/ui/label'
import { Separator } from '@/components/ui/separator'
import Image from 'next/image'
import { useTheme } from 'next-themes'
import { Terminal, Mail, Lock, User, ArrowRight, Eye, EyeOff, CircleDot } from 'lucide-react'

/* ═══════════════════════════════════════════════════════
   AUTH LOGO — Theme-aware logo for auth modals
   ═══════════════════════════════════════════════════════ */

function AuthLogo() {
  const { theme } = useTheme()
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    const id = requestAnimationFrame(() => setMounted(true))
    return () => cancelAnimationFrame(id)
  }, [])

  if (!mounted) {
    return (
      <div className="flex items-center gap-2.5 mb-6">
        <div className="w-7 h-7 rounded-md bg-[#00A8B5] flex items-center justify-center">
          <Terminal className="w-3.5 h-3.5 text-white" />
        </div>
        <span className="font-semibold text-lg tracking-[-0.02em] text-foreground" style={{ fontFamily: 'var(--font-display)' }}>
          Palm<span className="text-[#00A8B5]">kit</span>
        </span>
      </div>
    )
  }

  const isDark = theme === 'dark'

  return (
    <div className="mb-6">
      <Image
        src={isDark ? '/logo-dark.png' : '/logo-light.png'}
        alt="Palmkit"
        width={120}
        height={36}
        className="h-7 w-auto"
      />
    </div>
  )
}

/* ═══════════════════════════════════════════════════════
   AUTH MODAL TYPES
   ═══════════════════════════════════════════════════════ */

export type AuthView = 'login' | 'signup' | 'reset'

interface AuthModalsProps {
  open: boolean
  view: AuthView
  onViewChange: (view: AuthView) => void
  onClose: () => void
}

/* ═══════════════════════════════════════════════════════
   SHARED STYLES & COMPONENTS
   ═══════════════════════════════════════════════════════ */

const inputWrapperClass = "relative"
const inputIconClass = "absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground pointer-events-none"
const inputClass = "pl-10 h-11 bg-background border-border text-foreground placeholder:text-muted-foreground/60 focus-visible:border-pk-accent focus-visible:ring-pk-accent/20"

function EyebrowLabel({ children }: { children: React.ReactNode }) {
  return (
    <span className="label-eyebrow text-[#00A8B5] font-medium inline-flex items-center gap-2">
      <CircleDot className="w-1.5 h-1.5 fill-[#00A8B5]" />
      {children}
    </span>
  )
}

function PasswordInput({ 
  value, 
  onChange, 
  placeholder = "••••••••",
  id = "password"
}: { 
  value: string
  onChange: (v: string) => void
  placeholder?: string
  id?: string
}) {
  const [visible, setVisible] = useState(false)
  return (
    <div className={inputWrapperClass}>
      <Lock className={inputIconClass} />
      <Input
        id={id}
        type={visible ? 'text' : 'password'}
        placeholder={placeholder}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className={`${inputClass} pr-10`}
      />
      <button
        type="button"
        onClick={() => setVisible(!visible)}
        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
        aria-label={visible ? 'Hide password' : 'Show password'}
      >
        {visible ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
      </button>
    </div>
  )
}

/* ═══════════════════════════════════════════════════════
   LOGIN MODAL
   ═══════════════════════════════════════════════════════ */

function LoginForm({ onViewChange, onClose }: { onViewChange: (v: AuthView) => void; onClose: () => void }) {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [errors, setErrors] = useState<Record<string, string>>({})
  const [loading, setLoading] = useState(false)

  const validate = useCallback(() => {
    const errs: Record<string, string> = {}
    if (!email.trim()) errs.email = 'Email is required'
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) errs.email = 'Enter a valid email'
    if (!password) errs.password = 'Password is required'
    else if (password.length < 6) errs.password = 'Password must be at least 6 characters'
    return errs
  }, [email, password])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    const errs = validate()
    setErrors(errs)
    if (Object.keys(errs).length > 0) return
    setLoading(true)
    // Simulate API call
    setTimeout(() => {
      setLoading(false)
      onClose()
    }, 1500)
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-5">
      {/* Email */}
      <div className="space-y-2">
        <Label htmlFor="login-email" className="text-foreground text-[13px]">Email address</Label>
        <div className={inputWrapperClass}>
          <Mail className={inputIconClass} />
          <Input
            id="login-email"
            type="email"
            placeholder="you@company.com"
            value={email}
            onChange={(e) => { setEmail(e.target.value); setErrors((p) => ({ ...p, email: '' })) }}
            className={`${inputClass} ${errors.email ? 'border-destructive focus-visible:border-destructive focus-visible:ring-destructive/20' : ''}`}
            aria-invalid={!!errors.email}
          />
        </div>
        {errors.email && <p className="text-destructive text-xs mt-1">{errors.email}</p>}
      </div>

      {/* Password */}
      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <Label htmlFor="login-password" className="text-foreground text-[13px]">Password</Label>
          <button
            type="button"
            onClick={() => onViewChange('reset')}
            className="text-xs text-[#00A8B5] hover:text-[#33C4CF] transition-colors"
          >
            Forgot password?
          </button>
        </div>
        <PasswordInput
          id="login-password"
          value={password}
          onChange={(v) => { setPassword(v); setErrors((p) => ({ ...p, password: '' })) }}
        />
        {errors.password && <p className="text-destructive text-xs mt-1">{errors.password}</p>}
      </div>

      {/* Submit */}
      <Button
        type="submit"
        disabled={loading}
        className="w-full h-11 bg-foreground text-background hover:bg-foreground/90 font-medium text-sm gap-2"
      >
        {loading ? (
          <span className="flex items-center gap-2">
            <span className="w-4 h-4 border-2 border-background/30 border-t-background rounded-full animate-spin" />
            Signing in…
          </span>
        ) : (
          <>
            Log in
            <ArrowRight className="w-4 h-4" />
          </>
        )}
      </Button>

      {/* Divider */}
      <div className="relative">
        <Separator />
        <span className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-card px-3 text-muted-foreground text-xs">
          or
        </span>
      </div>

      {/* Social login placeholder */}
      <Button
        type="button"
        variant="outline"
        className="w-full h-11 border-border text-foreground hover:bg-muted/50 text-sm gap-2"
        onClick={() => {}}
      >
        <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none">
          <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4"/>
          <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
          <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
          <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
        </svg>
        Continue with Google
      </Button>

      {/* Switch to signup */}
      <p className="text-center text-sm text-muted-foreground">
        Don&apos;t have an account?{' '}
        <button
          type="button"
          onClick={() => onViewChange('signup')}
          className="text-foreground font-medium hover:text-[#00A8B5] transition-colors"
        >
          Sign up
        </button>
      </p>
    </form>
  )
}

/* ═══════════════════════════════════════════════════════
   SIGNUP MODAL
   ═══════════════════════════════════════════════════════ */

function SignupForm({ onViewChange, onClose }: { onViewChange: (v: AuthView) => void; onClose: () => void }) {
  const [name, setName] = useState('')
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [errors, setErrors] = useState<Record<string, string>>({})
  const [loading, setLoading] = useState(false)

  const validate = useCallback(() => {
    const errs: Record<string, string> = {}
    if (!name.trim()) errs.name = 'Name is required'
    if (!email.trim()) errs.email = 'Email is required'
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) errs.email = 'Enter a valid email'
    if (!password) errs.password = 'Password is required'
    else if (password.length < 8) errs.password = 'Password must be at least 8 characters'
    return errs
  }, [name, email, password])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    const errs = validate()
    setErrors(errs)
    if (Object.keys(errs).length > 0) return
    setLoading(true)
    setTimeout(() => {
      setLoading(false)
      onClose()
    }, 1500)
  }

  // Password strength
  const getPasswordStrength = () => {
    if (!password) return { label: '', color: '', width: '0%' }
    let score = 0
    if (password.length >= 8) score++
    if (/[A-Z]/.test(password)) score++
    if (/[0-9]/.test(password)) score++
    if (/[^A-Za-z0-9]/.test(password)) score++
    const levels = [
      { label: 'Weak', color: 'bg-red-500', width: '25%' },
      { label: 'Fair', color: 'bg-orange-500', width: '50%' },
      { label: 'Good', color: 'bg-[#00A8B5]', width: '75%' },
      { label: 'Strong', color: 'bg-emerald-500', width: '100%' },
    ]
    return levels[Math.min(score, 3)]
  }

  const strength = getPasswordStrength()

  return (
    <form onSubmit={handleSubmit} className="space-y-5">
      {/* Name */}
      <div className="space-y-2">
        <Label htmlFor="signup-name" className="text-foreground text-[13px]">Full name</Label>
        <div className={inputWrapperClass}>
          <User className={inputIconClass} />
          <Input
            id="signup-name"
            type="text"
            placeholder="Jane Smith"
            value={name}
            onChange={(e) => { setName(e.target.value); setErrors((p) => ({ ...p, name: '' })) }}
            className={`${inputClass} ${errors.name ? 'border-destructive focus-visible:border-destructive focus-visible:ring-destructive/20' : ''}`}
            aria-invalid={!!errors.name}
          />
        </div>
        {errors.name && <p className="text-destructive text-xs mt-1">{errors.name}</p>}
      </div>

      {/* Email */}
      <div className="space-y-2">
        <Label htmlFor="signup-email" className="text-foreground text-[13px]">Email address</Label>
        <div className={inputWrapperClass}>
          <Mail className={inputIconClass} />
          <Input
            id="signup-email"
            type="email"
            placeholder="you@company.com"
            value={email}
            onChange={(e) => { setEmail(e.target.value); setErrors((p) => ({ ...p, email: '' })) }}
            className={`${inputClass} ${errors.email ? 'border-destructive focus-visible:border-destructive focus-visible:ring-destructive/20' : ''}`}
            aria-invalid={!!errors.email}
          />
        </div>
        {errors.email && <p className="text-destructive text-xs mt-1">{errors.email}</p>}
      </div>

      {/* Password */}
      <div className="space-y-2">
        <Label htmlFor="signup-password" className="text-foreground text-[13px]">Password</Label>
        <PasswordInput
          id="signup-password"
          value={password}
          onChange={(v) => { setPassword(v); setErrors((p) => ({ ...p, password: '' })) }}
          placeholder="At least 8 characters"
        />
        {/* Password strength meter */}
        {password && (
          <div className="space-y-1.5">
            <div className="h-1 w-full bg-muted rounded-full overflow-hidden">
              <div
                className={`h-full rounded-full transition-all duration-300 ${strength.color}`}
                style={{ width: strength.width }}
              />
            </div>
            <p className="text-xs text-muted-foreground">
              Password strength: <span className="text-foreground font-medium">{strength.label}</span>
            </p>
          </div>
        )}
        {errors.password && <p className="text-destructive text-xs mt-1">{errors.password}</p>}
      </div>

      {/* Terms */}
      <p className="text-xs text-muted-foreground leading-relaxed">
        By creating an account, you agree to our{' '}
        <a href="#" className="text-foreground underline underline-offset-2 hover:text-[#00A8B5] transition-colors">Terms of Service</a>
        {' '}and{' '}
        <a href="#" className="text-foreground underline underline-offset-2 hover:text-[#00A8B5] transition-colors">Privacy Policy</a>
      </p>

      {/* Submit */}
      <Button
        type="submit"
        disabled={loading}
        className="w-full h-11 bg-foreground text-background hover:bg-foreground/90 font-medium text-sm gap-2"
      >
        {loading ? (
          <span className="flex items-center gap-2">
            <span className="w-4 h-4 border-2 border-background/30 border-t-background rounded-full animate-spin" />
            Creating account…
          </span>
        ) : (
          <>
            Create account
            <ArrowRight className="w-4 h-4" />
          </>
        )}
      </Button>

      {/* Divider */}
      <div className="relative">
        <Separator />
        <span className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-card px-3 text-muted-foreground text-xs">
          or
        </span>
      </div>

      {/* Social signup */}
      <Button
        type="button"
        variant="outline"
        className="w-full h-11 border-border text-foreground hover:bg-muted/50 text-sm gap-2"
        onClick={() => {}}
      >
        <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none">
          <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4"/>
          <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
          <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
          <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
        </svg>
        Continue with Google
      </Button>

      {/* Switch to login */}
      <p className="text-center text-sm text-muted-foreground">
        Already have an account?{' '}
        <button
          type="button"
          onClick={() => onViewChange('login')}
          className="text-foreground font-medium hover:text-[#00A8B5] transition-colors"
        >
          Log in
        </button>
      </p>
    </form>
  )
}

/* ═══════════════════════════════════════════════════════
   PASSWORD RESET MODAL
   ═══════════════════════════════════════════════════════ */

function ResetForm({ onViewChange, onClose }: { onViewChange: (v: AuthView) => void; onClose: () => void }) {
  const [email, setEmail] = useState('')
  const [errors, setErrors] = useState<Record<string, string>>({})
  const [loading, setLoading] = useState(false)
  const [sent, setSent] = useState(false)

  const validate = useCallback(() => {
    const errs: Record<string, string> = {}
    if (!email.trim()) errs.email = 'Email is required'
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) errs.email = 'Enter a valid email'
    return errs
  }, [email])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    const errs = validate()
    setErrors(errs)
    if (Object.keys(errs).length > 0) return
    setLoading(true)
    setTimeout(() => {
      setLoading(false)
      setSent(true)
    }, 1500)
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-5">
      {sent ? (
        <div className="text-center space-y-4 py-4">
          <div className="mx-auto w-12 h-12 rounded-full bg-emerald-500/10 flex items-center justify-center">
            <Mail className="w-5 h-5 text-emerald-500" />
          </div>
          <div className="space-y-2">
            <h3 className="text-foreground font-semibold text-lg">Check your email</h3>
            <p className="text-muted-foreground text-sm leading-relaxed">
              We&apos;ve sent a password reset link to{' '}
              <span className="text-foreground font-medium">{email}</span>. 
              Please check your inbox and follow the instructions.
            </p>
          </div>
          <Button
            type="button"
            onClick={() => onViewChange('login')}
            className="h-11 bg-foreground text-background hover:bg-foreground/90 font-medium text-sm gap-2"
          >
            <ArrowRight className="w-4 h-4 rotate-180" />
            Back to login
          </Button>
        </div>
      ) : (
        <>
          {/* Email */}
          <div className="space-y-2">
            <Label htmlFor="reset-email" className="text-foreground text-[13px]">Email address</Label>
            <div className={inputWrapperClass}>
              <Mail className={inputIconClass} />
              <Input
                id="reset-email"
                type="email"
                placeholder="you@company.com"
                value={email}
                onChange={(e) => { setEmail(e.target.value); setErrors((p) => ({ ...p, email: '' })) }}
                className={`${inputClass} ${errors.email ? 'border-destructive focus-visible:border-destructive focus-visible:ring-destructive/20' : ''}`}
                aria-invalid={!!errors.email}
              />
            </div>
            {errors.email && <p className="text-destructive text-xs mt-1">{errors.email}</p>}
          </div>

          {/* Submit */}
          <Button
            type="submit"
            disabled={loading}
            className="w-full h-11 bg-foreground text-background hover:bg-foreground/90 font-medium text-sm gap-2"
          >
            {loading ? (
              <span className="flex items-center gap-2">
                <span className="w-4 h-4 border-2 border-background/30 border-t-background rounded-full animate-spin" />
                Sending link…
              </span>
            ) : (
              <>
                Send reset link
                <ArrowRight className="w-4 h-4" />
              </>
            )}
          </Button>

          {/* Back to login */}
          <p className="text-center text-sm text-muted-foreground">
            Remember your password?{' '}
            <button
              type="button"
              onClick={() => onViewChange('login')}
              className="text-foreground font-medium hover:text-[#00A8B5] transition-colors"
            >
              Log in
            </button>
          </p>
        </>
      )}
    </form>
  )
}

/* ═══════════════════════════════════════════════════════
   MAIN AUTH MODALS COMPONENT
   ═══════════════════════════════════════════════════════ */

const viewConfig: Record<AuthView, { title: string; description: string; eyebrow: string }> = {
  login: {
    title: 'Welcome back',
    description: 'Sign in to your Palmkit account to continue building.',
    eyebrow: 'Sign in',
  },
  signup: {
    title: 'Create your account',
    description: 'Start building with Palmkit — no credit card required.',
    eyebrow: 'Get started',
  },
  reset: {
    title: 'Reset your password',
    description: 'Enter your email and we\'ll send you a link to reset your password.',
    eyebrow: 'Recover access',
  },
}

export function AuthModals({ open, view, onViewChange, onClose }: AuthModalsProps) {
  const config = viewConfig[view]

  return (
    <Dialog open={open} onOpenChange={(v) => !v && onClose()}>
      <DialogContent className="sm:max-w-[420px] border-border bg-card p-0 overflow-hidden">
        {/* Header with decorative top border */}
        <div className="h-1 bg-gradient-to-r from-[#00A8B5] via-[#4CD4B0] to-[#00A8B5]" />
        
        <div className="p-6 sm:p-8">
          {/* Logo */}
          <AuthLogo />

          <DialogHeader className="mb-6 text-left p-0">
            <EyebrowLabel>{config.eyebrow}</EyebrowLabel>
            <DialogTitle className="heading-display text-foreground text-2xl mt-2">
              {config.title}
            </DialogTitle>
            <DialogDescription className="text-muted-foreground text-sm mt-1">
              {config.description}
            </DialogDescription>
          </DialogHeader>

          {/* Animated form switching */}
          <AnimatePresence mode="wait">
            <motion.div
              key={view}
              initial={{ opacity: 0, x: view === 'signup' || view === 'reset' ? 20 : -20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: view === 'signup' || view === 'reset' ? -20 : 20 }}
              transition={{ duration: 0.2, ease: [0.22, 1, 0.36, 1] }}
            >
              {view === 'login' && <LoginForm onViewChange={onViewChange} onClose={onClose} />}
              {view === 'signup' && <SignupForm onViewChange={onViewChange} onClose={onClose} />}
              {view === 'reset' && <ResetForm onViewChange={onViewChange} onClose={onClose} />}
            </motion.div>
          </AnimatePresence>
        </div>
      </DialogContent>
    </Dialog>
  )
}

/* ═══════════════════════════════════════════════════════
   AUTH CONTEXT — Shared across all page sections
   ═══════════════════════════════════════════════════════ */

interface AuthModalContextType {
  openLogin: () => void
  openSignup: () => void
  openReset: () => void
}

const AuthModalContext = createContext<AuthModalContextType>({
  openLogin: () => {},
  openSignup: () => {},
  openReset: () => {},
})

export function useAuth() {
  return useContext(AuthModalContext)
}

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [open, setOpen] = useState(false)
  const [view, setView] = useState<AuthView>('login')

  const openLogin = useCallback(() => { setView('login'); setOpen(true) }, [])
  const openSignup = useCallback(() => { setView('signup'); setOpen(true) }, [])
  const openReset = useCallback(() => { setView('reset'); setOpen(true) }, [])
  const close = useCallback(() => setOpen(false), [])
  const changeView = useCallback((v: AuthView) => setView(v), [])

  return (
    <AuthModalContext.Provider value={{ openLogin, openSignup, openReset }}>
      {children}
      <AuthModals open={open} view={view} onViewChange={changeView} onClose={close} />
    </AuthModalContext.Provider>
  )
}

/* ═══════════════════════════════════════════════════════
   HOOK — Easy auth modal state management (standalone)
   ═══════════════════════════════════════════════════════ */

export function useAuthModal() {
  const [open, setOpen] = useState(false)
  const [view, setView] = useState<AuthView>('login')

  const openLogin = useCallback(() => { setView('login'); setOpen(true) }, [])
  const openSignup = useCallback(() => { setView('signup'); setOpen(true) }, [])
  const openReset = useCallback(() => { setView('reset'); setOpen(true) }, [])
  const close = useCallback(() => setOpen(false), [])
  const changeView = useCallback((v: AuthView) => setView(v), [])

  return { open, view, openLogin, openSignup, openReset, close, changeView }
}
